import { AES } from 'react-native-aes-crypto';
import Config from './config'; //assuming config file with encryption key exists 

export const encryptData = async (text) => {
    try{
        let encryptedText = await AES.encrypt(text, Config.ENCRYPTION_KEY);
        return encryptedText;
    }catch(error){
        console.log("Error in encryption: ", error);
    }
}

export const decryptData = async (encryptedText) => {
    try{
        let decryptedText = await AES.decrypt(encryptedText, Config.ENCRYPTION_KEY);
        return decryptedText;
    }catch(error){
        console.log("Error in decryption: ", error);
    }
}